#include "interface.h"

#include <cstdint>
#include <string>
#include <vector>

namespace {

static inline uint64_t mix(uint64_t hash, uint64_t value) {
  hash ^= value;
  hash *= 1099511628211ULL;
  return hash;
}

}  // namespace

uint64_t dictionary_groupby_checksum(
    const std::vector<std::string>& dictionary,
    const std::vector<uint16_t>& codes,
    const std::vector<uint32_t>& values,
    int iters) {
  const std::size_t dict_size = dictionary.size();
  const std::size_t n = codes.size();

  std::vector<uint64_t> sums(dict_size);
  uint64_t hash = 0;

  for (int iter = 0; iter < iters; ++iter) {
    for (std::size_t i = 0; i < dict_size; ++i) {
      sums[i] = 0;
    }

    const uint16_t* codes_ptr = codes.data();
    const uint32_t* values_ptr = values.data();

    std::size_t i = 0;
    const std::size_t unroll_end = n & ~std::size_t(3);
    for (; i < unroll_end; i += 4) {
      sums[static_cast<std::size_t>(codes_ptr[i])] += static_cast<uint64_t>(values_ptr[i]);
      sums[static_cast<std::size_t>(codes_ptr[i + 1])] += static_cast<uint64_t>(values_ptr[i + 1]);
      sums[static_cast<std::size_t>(codes_ptr[i + 2])] += static_cast<uint64_t>(values_ptr[i + 2]);
      sums[static_cast<std::size_t>(codes_ptr[i + 3])] += static_cast<uint64_t>(values_ptr[i + 3]);
    }
    for (; i < n; ++i) {
      sums[static_cast<std::size_t>(codes_ptr[i])] += static_cast<uint64_t>(values_ptr[i]);
    }

    hash = 1469598103934665603ULL;
    for (std::size_t k = 0; k < dict_size; ++k) {
      hash = mix(hash, sums[k]);
    }
  }

  return hash;
}
